思路：模拟
使用哈希表或者类似数据结构，记录每个人的生日月份。
遍历并统计生日月份为指定发放礼物月份的人数。
输出结果。
C++
#include<iostream>
#include<vector>
#include<string>
#include <utility>
#include <sstream>
#include<algorithm>
#include<cmath>
#include<map>
using namespace std;
//
通用 切割函数 函数 将字符串
str
根据
delimiter
进行切割
vector<string> split(const
string& str, const string& delimiter) {
vector<string>
result;
size_t start = 0;
size_t end = str.find(delimiter);
while (end !=
string::npos) {
result.push_back(str.substr(start, end - start));
start = end + delimiter.length();
end = str.find(delimiter, start);
}
//
添加最后一个部分
result.push_back(str.substr(start));
return result;
}
int main() {
int month;
string name;
string birthday;
cin >> month;
//
读取空格
cin.ignore();
getline(cin, name);
getline(cin, birthday);
vector<string>
names = split(name, " ");
vector<string>
birthdays = split(birthday, " ");
map<string, int>
nameMonth;
for (int i = 0; i <
names.size(); i++) {
string currentName = names[i];
string currentBirthday = birthdays[i];
nameMonth[currentName] = stoi(split(currentBirthday, "/")[1]);
}
//
统计
int count = 0;
for (auto &p :
nameMonth) {
if (p.second == month) {
count++;
}
}
cout << count;
return 0;
}
